import 'package:flutter_riverpod/flutter_riverpod.dart';

// ─────────────────────────────────────────────────────────
// Enums
// ─────────────────────────────────────────────────────────

enum DiseaseClass {
  cancer,
  neurological,
  cardiac,
  respiratory,
  renal,
  hepatic,
  hematological,
  autoimmune,
}

enum ContentDifficulty {
  basic,
  intermediate,
  detailed,
}

enum FaqCategory {
  general,
  treatment,
  sideEffects,
  nutrition,
  emotional,
  caregiver,
  endOfLife,
  financial,
}

// ─────────────────────────────────────────────────────────
// Data Models
// ─────────────────────────────────────────────────────────

class DiseaseEntry {
  final String id;
  final DiseaseClass diseaseClass;
  final String nameEn;
  final String nameHi;
  final String emoji;
  final String overviewEn;
  final String overviewHi;
  final List<DiseaseSection> sections;
  final List<String> keyFacts;
  final List<String> relatedDiseaseIds;
  final bool isBookmarked;
  final DateTime? lastReadAt;

  const DiseaseEntry({
    required this.id,
    required this.diseaseClass,
    required this.nameEn,
    required this.nameHi,
    required this.emoji,
    required this.overviewEn,
    required this.overviewHi,
    required this.sections,
    this.keyFacts = const [],
    this.relatedDiseaseIds = const [],
    this.isBookmarked = false,
    this.lastReadAt,
  });

  DiseaseEntry copyWith({
    bool? isBookmarked,
    DateTime? lastReadAt,
  }) {
    return DiseaseEntry(
      id: id,
      diseaseClass: diseaseClass,
      nameEn: nameEn,
      nameHi: nameHi,
      emoji: emoji,
      overviewEn: overviewEn,
      overviewHi: overviewHi,
      sections: sections,
      keyFacts: keyFacts,
      relatedDiseaseIds: relatedDiseaseIds,
      isBookmarked: isBookmarked ?? this.isBookmarked,
      lastReadAt: lastReadAt ?? this.lastReadAt,
    );
  }
}

class DiseaseSection {
  final String titleEn;
  final String titleHi;
  final String contentEn;
  final String contentHi;
  final ContentDifficulty difficulty;

  const DiseaseSection({
    required this.titleEn,
    required this.titleHi,
    required this.contentEn,
    required this.contentHi,
    this.difficulty = ContentDifficulty.basic,
  });
}

class FaqEntry {
  final String id;
  final FaqCategory category;
  final String questionEn;
  final String questionHi;
  final String answerEn;
  final String answerHi;
  final String? sourceNote;
  final bool isExpanded;

  const FaqEntry({
    required this.id,
    required this.category,
    required this.questionEn,
    required this.questionHi,
    required this.answerEn,
    required this.answerHi,
    this.sourceNote,
    this.isExpanded = false,
  });

  FaqEntry copyWith({bool? isExpanded}) {
    return FaqEntry(
      id: id,
      category: category,
      questionEn: questionEn,
      questionHi: questionHi,
      answerEn: answerEn,
      answerHi: answerHi,
      sourceNote: sourceNote,
      isExpanded: isExpanded ?? this.isExpanded,
    );
  }
}

// ─────────────────────────────────────────────────────────
// State
// ─────────────────────────────────────────────────────────

class DiseaseLibraryState {
  final List<DiseaseEntry> diseases;
  final List<FaqEntry> faqs;
  final DiseaseClass? selectedClass;
  final String? selectedDiseaseId;
  final FaqCategory? selectedFaqCategory;
  final String searchQuery;
  final bool isLoading;
  final List<String> bookmarkedIds;
  final List<String> recentlyViewedIds;

  const DiseaseLibraryState({
    this.diseases = const [],
    this.faqs = const [],
    this.selectedClass,
    this.selectedDiseaseId,
    this.selectedFaqCategory,
    this.searchQuery = '',
    this.isLoading = false,
    this.bookmarkedIds = const [],
    this.recentlyViewedIds = const [],
  });

  // ── Computed Getters ──

  List<DiseaseEntry> get filteredDiseases {
    var result = diseases.toList();

    if (selectedClass != null) {
      result = result.where((d) => d.diseaseClass == selectedClass).toList();
    }

    if (searchQuery.isNotEmpty) {
      final q = searchQuery.toLowerCase();
      result = result.where((d) =>
          d.nameEn.toLowerCase().contains(q) ||
          d.nameHi.contains(searchQuery) ||
          d.overviewEn.toLowerCase().contains(q)).toList();
    }

    return result;
  }

  DiseaseEntry? get selectedDisease {
    if (selectedDiseaseId == null) return null;
    try {
      return diseases.firstWhere((d) => d.id == selectedDiseaseId);
    } catch (_) {
      return null;
    }
  }

  List<FaqEntry> get filteredFaqs {
    if (selectedFaqCategory == null) return faqs;
    return faqs.where((f) => f.category == selectedFaqCategory).toList();
  }

  List<DiseaseEntry> get bookmarkedDiseases {
    return diseases.where((d) => d.isBookmarked).toList();
  }

  List<DiseaseEntry> get recentlyViewed {
    return recentlyViewedIds
        .map((id) {
          try {
            return diseases.firstWhere((d) => d.id == id);
          } catch (_) {
            return null;
          }
        })
        .whereType<DiseaseEntry>()
        .toList();
  }

  Map<DiseaseClass, int> get classCountMap {
    final map = <DiseaseClass, int>{};
    for (final d in diseases) {
      map[d.diseaseClass] = (map[d.diseaseClass] ?? 0) + 1;
    }
    return map;
  }

  DiseaseLibraryState copyWith({
    List<DiseaseEntry>? diseases,
    List<FaqEntry>? faqs,
    DiseaseClass? selectedClass,
    String? selectedDiseaseId,
    FaqCategory? selectedFaqCategory,
    String? searchQuery,
    bool? isLoading,
    List<String>? bookmarkedIds,
    List<String>? recentlyViewedIds,
    bool clearSelectedClass = false,
    bool clearSelectedDisease = false,
    bool clearSelectedFaqCategory = false,
  }) {
    return DiseaseLibraryState(
      diseases: diseases ?? this.diseases,
      faqs: faqs ?? this.faqs,
      selectedClass: clearSelectedClass ? null : (selectedClass ?? this.selectedClass),
      selectedDiseaseId: clearSelectedDisease ? null : (selectedDiseaseId ?? this.selectedDiseaseId),
      selectedFaqCategory: clearSelectedFaqCategory ? null : (selectedFaqCategory ?? this.selectedFaqCategory),
      searchQuery: searchQuery ?? this.searchQuery,
      isLoading: isLoading ?? this.isLoading,
      bookmarkedIds: bookmarkedIds ?? this.bookmarkedIds,
      recentlyViewedIds: recentlyViewedIds ?? this.recentlyViewedIds,
    );
  }
}

// ─────────────────────────────────────────────────────────
// Notifier
// ─────────────────────────────────────────────────────────

class DiseaseLibraryNotifier extends StateNotifier<DiseaseLibraryState> {
  DiseaseLibraryNotifier() : super(const DiseaseLibraryState()) {
    _loadData();
  }

  void _loadData() {
    state = state.copyWith(
      diseases: _mockDiseases,
      faqs: _mockFaqs,
      isLoading: false,
    );
  }

  // ── Navigation ──

  void selectClass(DiseaseClass? cls) {
    state = state.copyWith(
      selectedClass: cls,
      clearSelectedClass: cls == null,
      clearSelectedDisease: true,
    );
  }

  void selectDisease(String diseaseId) {
    // Track recently viewed
    final recent = [
      diseaseId,
      ...state.recentlyViewedIds.where((id) => id != diseaseId),
    ].take(10).toList();

    // Mark lastReadAt
    final updated = state.diseases.map((d) {
      if (d.id == diseaseId) return d.copyWith(lastReadAt: DateTime.now());
      return d;
    }).toList();

    state = state.copyWith(
      selectedDiseaseId: diseaseId,
      recentlyViewedIds: recent,
      diseases: updated,
    );
  }

  void clearDiseaseSelection() {
    state = state.copyWith(clearSelectedDisease: true);
  }

  // ── Search ──

  void updateSearch(String query) {
    state = state.copyWith(searchQuery: query);
  }

  void clearSearch() {
    state = state.copyWith(searchQuery: '');
  }

  // ── Bookmarks ──

  void toggleBookmark(String diseaseId) {
    final updated = state.diseases.map((d) {
      if (d.id == diseaseId) return d.copyWith(isBookmarked: !d.isBookmarked);
      return d;
    }).toList();

    final bookmarked = updated.where((d) => d.isBookmarked).map((d) => d.id).toList();

    state = state.copyWith(diseases: updated, bookmarkedIds: bookmarked);
  }

  // ── FAQ ──

  void selectFaqCategory(FaqCategory? cat) {
    state = state.copyWith(
      selectedFaqCategory: cat,
      clearSelectedFaqCategory: cat == null,
    );
  }

  void toggleFaqExpanded(String faqId) {
    final updated = state.faqs.map((f) {
      if (f.id == faqId) return f.copyWith(isExpanded: !f.isExpanded);
      return f;
    }).toList();
    state = state.copyWith(faqs: updated);
  }
}

// ─────────────────────────────────────────────────────────
// Provider
// ─────────────────────────────────────────────────────────

final diseaseLibraryProvider =
    StateNotifierProvider<DiseaseLibraryNotifier, DiseaseLibraryState>(
  (ref) => DiseaseLibraryNotifier(),
);

